define("local_xpstore/report",[],(function(){return{init:function(){document.querySelectorAll(".card-header-user").forEach((function(el){el.addEventListener("click",(function(){var userid=this.getAttribute("data-userid"),logsDiv=document.getElementById("logs-"+userid),iconDiv=document.getElementById("icon-"+userid);logsDiv.classList.contains("expanded")?(logsDiv.classList.remove("expanded"),iconDiv.className="fa fa-chevron-down text-muted"):(logsDiv.classList.add("expanded"),iconDiv.className="fa fa-chevron-up text-muted")}))}))}}}));